// Validate inputs the tool node passed in.
const i = $input.first().json;
const missing = ['role','target','argv'].filter(k => !(k in i));
if (missing.length) return [{ json: { ok: false, rejected_reason: 'missing: ' + missing.join(',') } }];
if (!Array.isArray(i.argv)) return [{ json: { ok: false, rejected_reason: 'argv must be array' } }];
return [{ json: i }];

// Surface a slim, LLM-friendly version of the response.
const r = $input.first().json;
return [{ json: {
  ok: !!r.ok,
  exit_code: r.exit_code ?? null,
  rejected_reason: r.rejected_reason ?? null,
  audit_id: r.audit_id ?? null,
  duration_ms: r.duration_ms ?? null,
  output: r.wrapped_for_llm || ('<tool_output trust="low">' + (r.stdout || '') + '</tool_output>')
} }];
